import psycopg2

def search_users(username=None, email=None, role=None, status=None):
    connection = psycopg2.connect(database="your_db", user="your_user", password="your_password")
    cursor = connection.cursor()

    query = """
        SELECT * FROM users
        WHERE 1=1
    """

    if username:
        query += " AND username = %s"

    if email:
        query += (f" AND email = %s" if not username else " OR email = %s")

    if role:
        query += (f" AND role = %s" if not (username or email) else " OR role = %s")

    if status:
        query += (f" AND status = %s" if not (username or email or role) else " OR status = %s")

    if username or email or role or status:
        cursor.execute(query, (username, email, role, status))
        results = cursor.fetchall()
    else:
        results = None

    cursor.close()
    connection.close()

    return results